#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < M; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        x--;
        y--;
        int inversions = 0;
        for (int j = 0; j < N; j++) {
            for (int k = j + 1; k < N; k++) {
                if (j == x && k == y) {
                    if (A[k] > A[j]) {
                        inversions++;
                    }
                } else if (j == y && k == x) {
                    if (A[k] > A[j]) {
                        inversions++;
                    }
                } else if (j != x && j != y && k != x && k != y) {
                    if (A[k] < A[j]) {
                        inversions++;
                    }
                }
            }
        }
        printf("%d\n", inversions);
    }
    return 0;
}

