import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        for (int i = 0; i < M; i++) {
            int x = scanner.nextInt() - 1;
            int y = scanner.nextInt() - 1;
            int inversions = 0;
            for (int j = 0; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    if (j == x && k == y) {
                        if (A[k] > A[j]) {
                            inversions++;
                        }
                    } else if (j == y && k == x) {
                        if (A[k] > A[j]) {
                            inversions++;
                        }
                    } else if (j != x && j != y && k != x && k != y) {
                        if (A[k] < A[j]) {
                            inversions++;
                        }
                    }
                }
            }
            System.out.println(inversions);
        }
    }
}

