    for (let j = 0; j < N; j++) {
        for (let k = j + 1; k < N; k++) {
            if (j === x - 1 && k === y - 1) {
                if (A[k] > A[j]) {
                    inversions++;
                }
            } else if (j === y - 1 && k === x - 1) {
                if (A[k] > A[j]) {
                    inversions++;
                }
            } else if (j !== x - 1 && j !== y - 1 && k !== x - 1 && k !== y - 1) {
                if (A[k] < A[j]) {
                    inversions++;
                }
            }
        }
    }
    console.log(inversions);
